import { Link, useLocation } from "react-router-dom";
import ''
export default function Navbar() {
  const location = useLocation();

  const links = [
    { path: "/dashboard", name: "Dashboard" },
    { path: "/projects", name: "Projects" },
    { path: "/taches", name: "Tasks" },
    { path: "/chat", name: "Chat" },
    { path: "/rapports", name: "Reports" },
  ];

  return (
    <nav className="navbar">
      <div className="logo">TaskFlow</div>

      <div className="nav-links">
        {links.map((link) => (
          <Link
            key={link.path}
            to={link.path}
            className={
              location.pathname === link.path ? "link active" : "link"
            }
          >
            {link.name}
          </Link>
        ))}
      </div>
    </nav>
  );
}

const styles = {
  nav: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "15px 30px",
    background: "#1e293b",
    color: "white",
  },
  logo: {
    margin: 0,
  },
  links: {
    display: "flex",
    gap: "20px",
  },
  link: {
    textDecoration: "none",
    color: "white",
    fontWeight: "500",
  },
  active: {
    borderBottom: "2px solid #38bdf8",
  },
};
